import React, { useState } from 'react';
import Layout from './components/Layout';
import Login from './pages/Login';

function App() {
  const [token, setToken] = useState(true); 
  const [view, setView] = useState('inicio'); // 1. Creamos el estado aquí

  if (!token) return <Login onLogin={setToken} />;

  return (
    /* 2. PASAMOS el setView al Layout para que los botones funcionen */
    <Layout setView={setView}> 
      
      {view === 'inicio' && (
        <div className="animate-in fade-in duration-500">
          <h1 className="text-6xl font-black mb-8 tracking-tighter">
            EXPLORA EL <span className="text-yellow-400">SONIDO</span>
          </h1>
          <div className="grid grid-cols-2 gap-6">
            <div className="bg-white/5 p-8 rounded-3xl border border-white/5 hover:border-yellow-400/50 transition-all cursor-pointer group">
              <p className="font-bold text-xl group-hover:text-yellow-400 transition">Flow RTN 2026</p>
              <p className="text-gray-500 text-sm">Tu dosis diaria de beats.</p>
            </div>
          </div>
        </div>
      )}

      {view === 'buscar' && (
        <div className="animate-in slide-in-from-bottom-4 duration-500">
          <h1 className="text-4xl font-bold mb-6">Busca en RTN MUSIC</h1>
          <input 
            type="text" 
            placeholder="Artistas, canciones o podcasts..." 
            className="w-full bg-white/5 border border-white/10 p-5 rounded-2xl outline-none focus:border-yellow-400 transition-all"
          />
        </div>
      )}

      {view === 'perfil' && (
        <div className="animate-in zoom-in-95 duration-500">
          <h1 className="text-4xl font-bold mb-6 text-yellow-400">Artist Zone</h1>
          <div className="bg-yellow-400/10 border border-yellow-400/20 p-10 rounded-[40px] text-center">
            <p className="text-xl font-medium mb-4">¿Listo para subir tu próximo hit?</p>
            <button className="bg-yellow-400 text-black px-8 py-3 rounded-full font-bold hover:scale-105 transition">
              Seleccionar Archivo .mp3
            </button>
          </div>
        </div>
      )}

    </Layout>
  );
}

export default App;
